previewCss:
.darma-loader-darma-custom-758 {
  color: var(--loader-color, #22c55e);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
height: 15px;
aspect-ratio: 5;
display: flex;
justify-content: space-between;
}
.darma-loader-darma-custom-758:before,
.darma-loader-darma-custom-758:after {
content: "";
width: calc(140%/3);
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: calc(300%/7) 100%;
transform-origin: calc(300%/14) 50%;
transform: translate(0) rotate(0);
animation: darma-loader-darma-custom-758-l33 1s infinite linear;
}
.darma-loader-darma-custom-758:after {
--s:-1;
transform-origin: calc(100% - calc(300%/14)) 50%;
}
@keyframes darma-loader-darma-custom-758-l33 {
100% {transform: translate(calc(var(--s,1)*(100% - calc(300%/7)))) rotate(calc(var(--s,1)_.5turn))}
}

